exercises.solution_code:
#include <iostream>
#include <format>

int main() {
    int fruit, workers;
    std::cin >> fruit >> workers;

    int per_worker = fruit / workers;
    int leftover   = fruit % workers;
    double exact   = static_cast<double>(fruit) / workers;

    std::cout << std::format("Each worker gets: {}\n", per_worker);
    std::cout << std::format("Leftover fruit: {}\n", leftover);
    std::cout << std::format("Exact per worker: {:.2f}\n", exact);

    return 0;
}

