#include <iostream>
#include <format>

int main() {
    int adult_price, child_price, total_tickets;
    std::cin >> adult_price >> child_price >> total_tickets;

    int child_tickets;
    std::cin >> child_tickets;

    int adult_tickets   = total_tickets - child_tickets;
    int revenue_cents   = adult_tickets * adult_price + child_tickets * child_price;
    int dollars         = revenue_cents / 100;
    int remaining_cents = revenue_cents % 100;

    std::cout << std::format("Adult tickets: {}\n", adult_tickets);
    std::cout << std::format("Total revenue (cents): {}\n", revenue_cents);
    std::cout << std::format("Total revenue: {} dollars and {} cents\n", dollars, remaining_cents);

    return 0;
}

