#include <cstdint>
#include <cstddef>
#include <iostream>
#include <string>

int main()
{
    int n{};
    std::cin >> n;

    size_t total{0};

    for (int i{1}; i <= n; ++i)
    {
        int bits{};
        std::cin >> bits;

        std::string typeName{};
        size_t byteSize{};

        if (bits == 8)
        {
            typeName = "int8_t";
            byteSize = sizeof(int8_t);
        }
        else if (bits == 16)
        {
            typeName = "int16_t";
            byteSize = sizeof(int16_t);
        }
        else if (bits == 32)
        {
            typeName = "int32_t";
            byteSize = sizeof(int32_t);
        }
        else
        {
            typeName = "int64_t";
            byteSize = sizeof(int64_t);
        }

        total += byteSize;

        std::cout << "Field " << i << ": " << typeName
                  << "  size=" << byteSize << "B"
                  << "  total=" << total << "B\n";
    }

    return 0;
}

