    double total{};
    for (int i{ 0 }; i < n; ++i)
        total += 1.0 / n;

    double total2{};
    for (int i{ 0 }; i < m; ++i)
        total2 += 1.0 / m;

    constexpr double epsilon{ 1e-9 };

    std::cout << std::boolalpha;
    std::cout << "Exact equal to 1: "          << (total == 1.0)                          << '\n';
    std::cout << "Nearly equal to 1: "         << (std::abs(total - 1.0) < epsilon)       << '\n';
    std::cout << "total and total2 nearly equal: " << (std::abs(total - total2) < epsilon) << '\n';

    return 0;
}

