#include <iostream>
#include <string>

namespace {
    std::string classifyLinkage(char kind) {
        switch (kind) {
            case 's': return "internal (static)";
            case 'a': return "internal (anonymous namespace)";
            case 'c': return "internal (const default)";
            case 'e': return "external";
            default:  return "unknown";
        }
    }
}

int main() {
    int n{};
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        char kind{};
        std::cin >> kind;
        std::cout << classifyLinkage(kind) << '\n';
    }
    return 0;
}

