exercises.solution_code:
#include <iostream>
#include <iomanip>

namespace {
    double clamp(double value, double lo, double hi) {
        if (value < lo) return lo;
        if (value > hi) return hi;
        return value;
    }

    double normalize(double value, double lo, double hi) {
        return (value - lo) / (hi - lo);
    }
}

void normalizeValue(double value, double lo, double hi) {
    double clamped = clamp(value, lo, hi);
    std::cout << std::fixed << std::setprecision(4);
    std::cout << "Clamped: " << clamped << "\n";
    double normed = normalize(clamped, lo, hi);
    std::cout << "Normalized: " << normed << "\n";
}

int main() {
    double value, lo, hi;
    std::cin >> value >> lo >> hi;
    normalizeValue(value, lo, hi);
    return 0;
}

