#include <array>
#include <iostream>
#include <string>
#include <print>

template <std::size_t N>
void printRepeated(const std::array<int, N>& arr) {
    bool first = true;
    for (std::size_t pass = 0; pass < 2; ++pass) {
        for (std::size_t i = 0; i < N; ++i) {
            if (!first) std::print(" ");
            std::print("{}", arr[i]);
            first = false;
        }
    }
}

template <std::size_t N>
void printReversed(const std::array<int, N>& arr) {
    for (std::size_t i = N; i-- > 0; ) {
        if (i != N - 1) std::print(" ");
        std::print("{}", arr[i]);
    }
}

template <std::size_t N>
void dispatch(const std::string& mode, const std::array<int, 10>& buf) {
    std::array<int, N> arr{};
    for (std::size_t i = 0; i < N; ++i) arr[i] = buf[i];
    if (mode == "repeated")  printRepeated(arr);
    else                     printReversed(arr);
}

