#include <iostream>
#include <string>
#include <sstream>

int count_words(const std::string& s)
{
    std::istringstream ss{s};
    int count{0};
    std::string token{};
    while (ss >> token) ++count;
    return count;
}

int longest_word(const std::string& s)
{
    std::istringstream ss{s};
    int best{0};
    std::string token{};
    while (ss >> token)
    {
        int len{static_cast<int>(token.size())};
        if (len > best) best = len;
    }
    return best;
}

int main()
{
    std::string line{};
    std::getline(std::cin, line);

    std::cout << "Words: " << count_words(line) << '\n';
    std::cout << "Longest: " << longest_word(line) << '\n';

    return 0;
}

