#include <iostream>
#include <iomanip>

double average(const int* data, int size) {
    double sum{ 0.0 };
    for (int i{ 0 }; i < size; ++i)
        sum += data[i];
    return sum / size;
}

const int& maxElement(const int* data, int size) {
    int best{ 0 };
    for (int i{ 1 }; i < size; ++i)
        if (data[i] > data[best])
            best = i;
    return data[best];
}

void scale(int* data, int size, int factor) {
    for (int i{ 0 }; i < size; ++i)
        data[i] *= factor;
}

int main() {
    int n{};
    std::cin >> n;

