    Sensor(std::string name, double temperature)
        : Sensor{ std::move(name), temperature, 1 }
    {}

    explicit Sensor(std::string name)
        : Sensor{ std::move(name), 0.0 }
    {}

    Sensor()
        : Sensor{ "default" }
    {}

    void report() const
    {
        std::cout << std::fixed << std::setprecision(1);
        std::cout << "Sensor " << name << ": " << temperature << "C ("
                  << count << " sample(s))\n";
    }
};

int main()
{
    std::string name;
    double temperature;
    int count;
    std::cin >> name >> temperature >> count;

    Sensor s1{ name, temperature, count };
    Sensor s2{ name, temperature };
    Sensor s3{ name };
    Sensor s4{};

    s1.report();
    s2.report();
    s3.report();
    s4.report();

    return 0;
}

