#include <iostream>
#include <string>
#include <format>

struct Student {
private:
    std::string name;
    int grades[5]{};
    int count{};

public:
    Student(const std::string& n, const int* g, int cnt)
        : name{n}, count{cnt} {
        for (int i = 0; i < count; ++i)
            grades[i] = g[i];
    }

    Student(const Student& src) : count{src.count} {
        std::cout << std::format("Copy constructor called for: {}\n", src.name);
        name = src.name;
        for (int i = 0; i < count; ++i)
            grades[i] = src.grades[i];
    }

    double average() const {
        double sum = 0;
        for (int i = 0; i < count; ++i)
            sum += grades[i];
        return sum / count;
    }

    const std::string& getName() const { return name; }

    int getGrade(int i) const { return grades[i]; }

    void rename(const std::string& newName) { name = newName; }

    int getCount() const { return count; }
};

int main() {
    std::string name;
    int n;
    std::cin >> name >> n;

    int g[5]{};
    for (int i = 0; i < n; ++i)
        std::cin >> g[i];

    Student original{name, g, n};
    Student copy = original;
    copy.rename("Clone");

    std::cout << std::format("Original: {} avg={:.2f}\n", original.getName(), original.average());
    // Note: copy constructor line already printed above
    std::cout << std::format("Copy: {} avg={:.2f}\n", copy.getName(), copy.average());
    std::cout << std::format("After rename, original: {} avg={:.2f}\n", original.getName(), original.average());
    std::cout << std::format("After rename, copy: {} avg={:.2f}\n", copy.getName(), copy.average());

    bool match = true;
    for (int i = 0; i < original.getCount(); ++i)
        if (original.getGrade(i) != copy.getGrade(i)) { match = false; break; }
    std::cout << std::format("Grades match: {}\n", match ? "yes" : "no");

    return 0;
}

