    Rectangle scaled = scale(sq, f);

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Rectangle area: " << rect.area() << "\n";
    std::cout << "Square area: " << sq.area() << "\n";
    std::cout << "Scaled square area: " << scaled.area() << "\n";

    return 0;
}

