exercises.solution_code:
#include <algorithm>
#include <cctype>
#include <iostream>
#include <string>

struct TextLine
{
    std::string text;

    TextLine(std::string start) : text{ std::move(start) } {}

    TextLine& append(const std::string& word)
    {
        text += ' ';
        text += word;
        return *this;
    }

    TextLine& toUpper()
    {
        std::transform(text.begin(), text.end(), text.begin(),
                       [](unsigned char c){ return static_cast<char>(std::toupper(c)); });
        return *this;
    }

    TextLine& toLower()
    {
        std::transform(text.begin(), text.end(), text.begin(),
                       [](unsigned char c){ return static_cast<char>(std::tolower(c)); });
        return *this;
    }

    // printBefore and printAfter must return const TextLine& so they can be
    // called on a const-qualified *this, yet the next mutable call (toUpper/
    // toLower) is valid because the underlying object is non-const.
    const TextLine& printBefore() const
    {
        std::cout << "Before: " << text << '\n';
        return *this;
    }

    const TextLine& printAfter() const
    {
        std::cout << "After: " << text << '\n';
        return *this;
    }
};

int main()
{
    std::string word1{}, word2{};
    char mode{};
    std::cin >> word1 >> word2 >> mode;

    if (mode == 'U')
    {
        TextLine(word1).append(word2).printBefore().toUpper().printAfter();
    }
    else
    {
        TextLine(word1).append(word2).printBefore().toLower().printAfter();
    }

    return 0;
}

