#include <iostream>
#include <vector>
#include <algorithm>
#include <iomanip>

class TempLog {
public:
    TempLog& add(double t);
    int count() const;
    double minTemp() const;
    double maxTemp() const;
private:
    std::vector<double> m_readings;
};

TempLog& TempLog::add(double t) {
    m_readings.push_back(t);
    return *this;
}

int TempLog::count() const {
    return static_cast<int>(m_readings.size());
}

double TempLog::minTemp() const {
    return *std::min_element(m_readings.begin(), m_readings.end());
}

double TempLog::maxTemp() const {
    return *std::max_element(m_readings.begin(), m_readings.end());
}

