class Temperature {
    T m_celsius;

    explicit Temperature(T celsius) : m_celsius{ celsius } {}

public:
    static Temperature<T> fromCelsius(T c) {
        return Temperature<T>{ c };
    }

    static Temperature<T> fromFahrenheit(T f) {
        return Temperature<T>{ (f - 32) * 5 / 9 };
    }

    T celsius()    const { return m_celsius; }
    T fahrenheit() const { return m_celsius * 9 / 5 + 32; }
};

