    std::cin >> mode >> value;

    Temperature<double> temp =
        (mode == 'C') ? Temperature<double>::fromCelsius(value)
                      : Temperature<double>::fromFahrenheit(value);

    std::cout << std::fixed << std::setprecision(1);
    std::cout << "Celsius: "    << temp.celsius()    << '\n';
    std::cout << "Fahrenheit: " << temp.fahrenheit() << '\n';

