public:
    TempLog(double temp) : m_temp{ temp } {
        ++s_count;
        s_sum += m_temp;
    }

    static int    getCount()   { return s_count; }
    static double getSum()     { return s_sum; }
    static double getAverage() { return s_sum / s_count; }
};

int    TempLog::s_count{ 0 };
double TempLog::s_sum{ 0.0 };

int main() {
    int n;
    std::cin >> n;

    std::vector<TempLog> logs;
    logs.reserve(n);
    for (int i = 0; i < n; ++i) {
        double t;
        std::cin >> t;
        logs.emplace_back(t);
    }

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Count: "   << TempLog::getCount()   << "\n";
    std::cout << "Sum: "     << TempLog::getSum()     << "\n";
    std::cout << "Average: " << TempLog::getAverage() << "\n";

    return 0;
}

