exercises.solution_code:
#include <iostream>
#include <memory>

struct Device {
    int id;
    Device(int id) : id(id) {
        std::cout << "Device " << id << " created\n";
    }
    ~Device() {
        std::cout << "Device " << id << " destroyed\n";
    }
};

std::unique_ptr<Device> transferOwnership(std::unique_ptr<Device> d) {
    std::cout << "Transferring ownership of device " << d->id << "\n";
    return std::move(d);
}

int main() {
    int id;
    std::cin >> id;

    auto original = std::make_unique<Device>(id);
    auto received = transferOwnership(std::move(original));

    std::cout << "Main holds device " << received->id << "\n";

    return 0;
}

