exercises.solution_code:
#include <iostream>
#include <memory>

struct Resource {
    int id;
    Resource(int id) : id(id) {
        std::cout << "Resource " << id << " created\n";
    }
    ~Resource() {
        std::cout << "Resource " << id << " destroyed\n";
    }
};

int main() {
    int id;
    std::cin >> id;

    auto first = std::make_shared<Resource>(id);
    std::cout << "After first owner: count = " << first.use_count() << "\n";

    auto second = first;  // shared ownership — copy, not move
    std::cout << "After second owner: count = " << first.use_count() << "\n";

    first.reset();
    std::cout << "After reset of first owner: count = " << second.use_count() << "\n";

    second.reset();  // destructor fires here
    std::cout << "After reset of second owner: count = 0\n";

    return 0;
}
